import tensorflow as tf
from tensorflow.keras import layers

# WRONG: layer created inside call() — weights re-created each call
class WrongBlock(layers.Layer):
    def call(self, x):
        dense = layers.Dense(64)   # new layer on every call!
        return dense(x)

# RIGHT: layer created in __init__()
class CorrectBlock(layers.Layer):
    def __init__(self):
        super().__init__()
        self.dense = layers.Dense(64)   # created once

    def call(self, x):
        return self.dense(x)

# WRONG: manual preprocessing outside the model
