    return model.predict(tokens)

# RIGHT: preprocessing inside model
def right_predict(model, raw_text):
    return model.predict(raw_text)    # model handles tokenization internally

# Training mode matters for BatchNorm / Dropout
model = tf.keras.Sequential([
    layers.Dense(64, activation='relu'),
    layers.Dropout(0.5),
    layers.BatchNormalization(),
    layers.Dense(10, activation='softmax'),
])
x = tf.random.normal((1, 32))

train_out = model(x, training=True)   # dropout active, BN uses batch stats
infer_out = model(x, training=False)  # dropout off, BN uses moving stats
print("Outputs differ:", not tf.reduce_all(tf.equal(train_out, infer_out)).numpy())
